// Shared documentation search, used by the NLWeb /ask endpoint and the MCP
// server (/api/mcp). Deterministic title/description scoring over the Fumadocs
// page source — no external service, no file reads for ranking.

import { readDocBody } from "@/lib/docs-content";
import { SITE } from "@/lib/constants";
import { source } from "@/lib/source";

export type DocHit = {
	id: string;
	title: string;
	url: string;
	content: string;
};

export function searchDocs(query: string, max = 10): DocHit[] {
	const terms = query
		.toLowerCase()
		.split(/[^a-z0-9]+/)
		.filter((t) => t.length > 1);
	if (terms.length === 0) return [];

	const scored: Array<DocHit & { score: number }> = [];
	for (const page of source.getPages()) {
		const title = (page.data.title ?? "").toLowerCase();
		const desc = (page.data.description ?? "").toLowerCase();
		let score = 0;
		for (const term of terms) {
			if (title.includes(term)) score += 3;
			if (desc.includes(term)) score += 1;
		}
		if (score > 0) {
			scored.push({
				id: page.url,
				title: page.data.title ?? page.url,
				url: `${SITE.domain}${page.url}`,
				content: page.data.description ?? "",
				score,
			});
		}
	}
	return scored
		.sort((a, b) => b.score - a.score)
		.slice(0, max)
		.map(({ score: _score, ...hit }) => hit);
}

// Fetch a single doc page's Markdown by its URL path (e.g. "/docs/foo") or its
// slug ("foo/bar"). Returns null when the page doesn't exist.
export async function getDocMarkdown(pathOrSlug: string): Promise<string | null> {
	const slug = pathOrSlug
		.replace(/^\/+/, "")
		.replace(/^docs\//, "")
		.split("/")
		.filter(Boolean);
	const page = source.getPage(slug);
	if (!page) return null;
	const body = await readDocBody(page.slugs);
	return `# ${page.data.title}\n\n${page.data.description ?? ""}\n\n${body ?? ""}\n`;
}
